import re
import codecs

new_decree_data = """const List<DecreeArticle> decreeData = [
  DecreeArticle(id: '1', title: 'المكاتب المتبارى عليها', content: 'يحدد عدد المكاتب المتبارى عليها بدائرة كل محكمة ابتدائية بقرار لوزير العدل.'),
  DecreeArticle(id: '2', title: 'مواد المباراة', content: 'تشتمل المباراة على اختبارين كتابي وشفوي:\\nيشتمل الاختبار الكتابي على:\\n- موضوع يتعلق بقانون الالتزامات والعقود، مدته ساعتان بمعامل 2 ؛\\n- موضوع يتعلق بقانون المسطرة المدنية، مدته ساعتان بمعامل 2 ؛\\nيشتمل الاختبار الشفوي على:\\n- عرض يتعلق بالتنظيم القضائي، مدة تهييئه عشرون دقيقة بمعامل 1 ؛\\n- عرض يتعلق بالقانون المنظم لمهنة المفوضين القضائيين، مدة تهييئه عشرون دقيقة بمعامل 1.'),
  DecreeArticle(id: '3', title: 'تقييم المباراة', content: 'تقيم كل مادة بدرجات تتراوح بين 0 و 20.\\nلا يعتبر ناجحا في الاختبار الكتابي من لم يحصل في كل مادة على عدد من النقط لا يقل عن 10.\\nلا يعتبر في الترتيب النهائي من لم يحصل على مجموع من النقط لا يقل عن 60.\\nيرتب الناجحون لشغل المكاتب المتبارى عليها حسب الاستحقاق. إذا تساوى المترشحون في النقط المحصل عليها تم اللجوء إلى القرعة عند الاقتضاء.'),
  DecreeArticle(id: '4', title: 'تنظيم المباراة', content: 'تحدد كيفية تنظيم المباراة بقرار لوزير العدل.'),
  DecreeArticle(id: '5', title: 'فترة التكوين', content: 'يقضي المتدرب فترة التكوين التي تحدد في ستة أشهر بالمعهد العالي للقضاء، وبتنسيق مع مديرية الشؤون المدنية.\\nتشتمل هذه الفترة على:\\n(أ) طور للدراسات والأشغال التطبيقية بالمعهد العالي للقضاء مدته ثلاثة أشهر، يرمي إلى تأهيله لمزاولة مهنة مفوض قضائي بواسطة تعليم خاص، يشمل على الخصوص المقتضيات القانونية المتعلقة بتنظيم مهنة المفوضين القضائيين والقواعد المسطرية المتعلقة بالتبليغ وبإجراءات تنفيذ الأوامر والأحكام والقرارات وكل العقود والسندات التي لها قوة تنفيذية، وكذا مختلف الإجراءات القضائية الأخرى؛\\n(ب) تدريب مدته ثلاثة أشهر بكتابة ضبط المحاكم الابتدائية والتجارية والإدارية وكتابة ضبط محاكم الاستئناف، وبمكاتب مفوضين قضائيين تحدد باقتراح من رئيس الهيئة الوطنية للمفوضين القضائيين أو من ينوب عنه.\\nلا تصرف للمتدرب أي أجرة خلال فترة التكوين.\\nيجرى التكوين تحت إشراف المعهد العالي للقضاء طيلة فترة التكوين وكذا تحت مراقبة الوكيل العام للملك خلال مدة مقام المتدرب في محكمة أو لدى مفوض قضائي.'),
  DecreeArticle(id: '6', title: 'استغراق التكوين', content: 'يجب أن يستغرق التكوين لدى كتابة ضبط المحكمة أو لدى مفوض قضائي ساعات العمل العادية المفروضة على الموظفين الإداريين أو المستخدمين التابعين للمفوض القضائي ولا يمكن أن ينقطع إلا لأسباب مقبولة.'),
  DecreeArticle(id: '7', title: 'اختبار نهاية التكوين', content: 'يشتمل اختبار نهاية التكوين على اختبارين كتابي وشفوي.\\nيشتمل الاختبار الكتابي على:\\n- موضوع في قانون المسطرة المدنية، مدته ساعتان بمعامل 2.\\n- وسيلة من تحرير ثلاثة مشاريع محررات تتعلق بالإجراءات أمام المحاكم وبممارسة وسائل التنفيذ، مدته ساعتان بمعامل 2.\\nيشتمل الاختبار الشفوي على:\\n- عرض قانوني له علاقة بأعمال المفوضين القضائيين، مدة تهييئه عشرون دقيقة بمعامل 1 ؛\\n- عرض يتعلق بالمعلوميات بمعامل 1.'),
  DecreeArticle(id: '8', title: 'تقييم اختبار النهاية', content: 'تقيم كل مادة بدرجات تتراوح بين 0 و 20.\\nلا يعتبر أيا كان في الترتيب النهائي إن لم يحصل على معدل لا يقل عن 60.'),
  DecreeArticle(id: '9', title: 'كيفية الاختبار', content: 'تحدد كيفية تنظيم اختبار نهاية التكوين بقرار لوزير العدل.'),
  DecreeArticle(id: '10', title: 'اللجنة المشرفة للمباراة', content: 'تتركب اللجنة المشرفة على المباراة واختبار نهاية التكوين من:\\n- مدير الشؤون المدنية بصفته رئيسا ؛\\n- المدير العام للمعهد العالي للقضاء ؛\\n- أربعة رؤساء أولين لمحاكم الاستئناف ؛\\n- أربعة وكلاء عامين للملك لدى محاكم الاستئناف ؛\\n- رئيس الهيئة الوطنية للمفوضين القضائيين أو من ينتدبه لهذه الغاية.'),
  DecreeArticle(id: '11', title: 'تعيين اللجنة', content: 'يعين وزير العدل أعضاء اللجنة المشرفة على المباراة واختبار نهاية التكوين وكذا نوابا لهم بقرار.'),
  DecreeArticle(id: '12', title: 'تأليف اللجنة المادة 9', content: 'تتألف اللجنة المذكورة في المادة 9 من القانون 81.03 من:\\n- مدير الشؤون المدنية بصفته رئيسا ؛\\n- رئيس أول لمحكمة استئناف ؛\\n- وكيل عام للملك لدى محكمة استئناف ؛\\n- ممثلين اثنين للمفوضين القضائيين تنتدبهما الهيئة الوطنية للمفوضين القضائيين.'),
  DecreeArticle(id: '13', title: 'اجتماع اللجنة', content: 'تجتمع اللجنة باستدعاء من وزير العدل كلما اقتضت المصلحة ذلك للبت في القضايا التي تدخل في اختصاصها.\\nتعتبر اجتماعات اللجنة صحيحة بحضور ثلاثة من أعضائها على الأقل بمن فيهم الرئيس.\\nيتولى مهام كتابة اللجنة موظف بمديرية الشؤون المدنية. ترفع هذه اللجنة مقترحاتها إلى وزير العدل.'),
  DecreeArticle(id: '14', title: 'التعويضات والأجور', content: 'يحدد بقرار مشترك لوزير العدل ووزير المالية التعويض الذي يتقاضاه المفوضون القضائيون عن مزاولة مهامهم في الميدان الجنائي، وتعريفة أجورهم عن الأعمال التي يقومون بها في الميادين المدنية والتجارية والإدارية.'),
  DecreeArticle(id: '15', title: 'مهام الهيئة الوطنية', content: 'تتولى الهيئة الوطنية للمفوضين القضائيين التي تتفرع عنها مجالس جهوية على صعيد دوائر محاكم الاستئناف المهام التالية:\\n- صيانة مبادئ وتقاليد وأعراف المهنة، والحرص على تثبيت أخلاقياتها، وعلى تقيد المفوضين القضائيين بواجباتهم المهنية، والسهر على حماية حقوقهم ؛\\n- إبداء الرأي في الشكايات الموجهة إليها ضد المفوضين القضائيين ورفع تقرير بشأنها إلى وكيل الملك، وكذا فيما يعرض عليها من طرف النيابة العامة من إخلالات منسوبة لأي مفوض قضائي ؛\\n- تنسيق عمل المجالس الجهوية للمفوضين القضائيين ؛\\n- وضع النظام الداخلي وتعديله ؛\\n- تحديد مبلغ اشتراكات الأعضاء وكيفية استيفائها، والقسط الذي يخص المجالس الجهوية ؛\\n- إنشاء وإدارة مشاريع اجتماعية لفائدة المفوضين القضائيين ؛\\n- إبرام عقود التأمين على المسؤولية المدنية والتغطية الصحية ؛\\n- السهر على تنظيم لقاءات وندوات علمية من شأنها أن ترفع من مستوى الأداء، وأن تضمن تطوير وتحديث أساليب المهنة ؛\\n- طبع السجل والكناش المنصوص عليهما على التوالي في المادتين 25 و 29 من القانون رقم 81.03 المشار إليه أعلاه، بعد إذن وزير العدل.'),
  DecreeArticle(id: '16', title: 'تمثيل المهنة', content: 'تمثل الهيئة الوطنية للمفوضين القضائيين المهنة تجاه الإدارة، وتبدي رأيها فيما يعرض عليها من مسائل تتعلق بالممارسة العامة للمهنة وتقدم المقترحات الكفيلة بتطوير المهنة.'),
  DecreeArticle(id: '17', title: 'واجب الاشتراك', content: 'يفرض لفائدة الهيئة الوطنية للمفوضين القضائيين اشتراك سنوي إجباري يجب على كل مفوض قضائي أن يقوم بأدائه.'),
  DecreeArticle(id: '18', title: 'مالية الهيئة', content: 'تتكون مالية الهيئة الوطنية للمفوضين القضائيين من الموارد التي لا يمنعها القانون ولا سيما:\\n- واجبات الاشتراك ؛\\n- عائدات السجلات وكناش تواصيل الأداء ؛\\n- عائدات المطبوعات والكتب والدوريات.'),
  DecreeArticle(id: '19', title: 'المساعدات والتبرعات', content: 'يجوز للهيئة الوطنية للمفوضين القضائيين أن تحصل على مساعدات نقدية أو عينية من الدولة والمؤسسات العامة.\\nيجوز لها كذلك أن تتلقى من الأشخاص الذاتيين أو المعنويين أي تبرع على أن لا يكون مقيدا بأي شرط من شأنه المساس باستقلالها وكرامتها أو يخالف القوانين والأنظمة المعمول بها.'),
  DecreeArticle(id: '20', title: 'إنفاق الموارد المالية', content: 'تنفق الموارد المالية في تجهيز الهيئة الوطنية والمجالس الجهوية للمفوضين القضائيين وتسيير شؤونها وما يتعلق بإدارة مقارها، وأداء أجور العاملين بها، والوفاء بكل التزاماتها وتحملاتها، وفي إنشاء وإدارة مشاريع اجتماعية وتنظيم تظاهرات ثقافية.'),
  DecreeArticle(id: '21', title: 'أجهزة الهيئة الوطنية', content: 'تمارس الهيئة الوطنية للمفوضين القضائيين اختصاصاتها بواسطة أجهزتها التالية:\\n- الجمعية العامة ؛\\n- رئيس الهيئة الوطنية للمفوضين القضائيين ؛\\n- المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين ؛\\n- المجالس الجهوية للمفوضين القضائيين.'),
  DecreeArticle(id: '22', title: 'الجمعية العامة', content: 'الجمعية العامة هي أعلى جهاز يحدد التوجهات الكبرى للهيئة.\\nتتكون الجمعية العامة من رئيس الهيئة الوطنية ورؤساء وأعضاء مكاتب المجالس الجهوية، وهي أعلى سلطة تقريرية.\\nتجتمع الجمعية العامة بالرباط أو بأي مدينة من مدن المملكة، مرة كل ثلاث سنوات لانتخاب رئيس الهيئة الوطنية للمفوضين القضائيين واستثناء كلما دعت المصلحة إلى ذلك بطلب من الرئيس أو من ثلثي أعضاء المكتب التنفيذي.'),
  DecreeArticle(id: '23', title: 'صفة الناخب', content: 'لا يتمتع بصفة ناخب إلا المفوض القضائي الذي يمارس المهنة بصفة فعلية وأدى ما عليه من واجبات الاشتراك.'),
  DecreeArticle(id: '24', title: 'انتخاب الرئيس', content: 'ينتخب رئيس الهيئة للمفوضين القضائيين خلال النصف الثاني من شهر ماي، عن طريق الاقتراع الفردي السري المباشر وبالأغلبية النسبية للأعضاء الحاضرين على ألا يقل عددهم عن نصف أعضاء الجمعية العامة، وفي حالة عدم اكتمال النصاب يؤجل الاجتماع لمدة شهر، وفي هذه الحالة يتم الانتخاب بالأغلبية النسبية للأعضاء الحاضرين.\\nيرجح في الانتخاب عند تعادل الأصوات المفوض القضائي الأقدم ممارسة في المهنة.'),
  DecreeArticle(id: '25', title: 'شروط الترشح للرئاسة', content: 'يشترط في المترشح لرئاسة الهيئة الوطنية للمفوضين القضائيين الشروط التالية:\\n- أن تكون له صفة ناخب ؛\\n- أن تكون له أقدمية عشر سنوات من الممارسة على الأقل ؛\\n- أن لا يكون قد صدرت في حقه عقوبة تأديبية، باستثناء عقوبة الإنذار ؛\\n- أن لا يكون محكوما عليه أو متابعا في قضية تمس بالشرف والمروءة.'),
  DecreeArticle(id: '26', title: 'مدة الرئاسة للتجديد', content: 'ينتخب رئيس الهيئة الوطنية للمفوضين القضائيين لمدة ثلاث سنوات قابلة للتجديد مرة واحدة.\\nلا يمكن إعادة انتخاب رئيس الهيئة الوطنية للمفوضين القضائيين الذي استمرت مهمته فترتين متواليتين إلا بعد انصرام مدة ثلاث سنوات كاملة على آخر فترة.'),
  DecreeArticle(id: '27', title: 'لوائح الترشيح والطعن', content: 'يصدر المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين خلال النصف الأول من شهر مارس من السنة التي تجرى فيها الانتخابات مقررا بتحديد أسماء المفوضين القضائيين المتوفرين على الشروط المطلوبة قانونا ويعلق بمقار المجالس الجهوية للمفوضين القضائيين داخل الأجل المذكور.\\nيحق لكل مفوض قضائي لم يرد اسمه في مقرر المكتب التنفيذي الطعن فيه أمام المحكمة الإدارية بالرباط داخل أجل ثمانية أيام من تاريخ التعليق، وتبت فيه داخل أجل خمسة عشر يوما من تاريخ إيداع الطعن بكتابة ضبط المحكمة، وذلك بحكم غير قابل لأي طعن.\\nتوجه إلى المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين الترشيحات لرئاسة الهيئة الوطنية داخل أجل شهر من تاريخ تعليق المقرر.'),
  DecreeArticle(id: '28', title: 'تبليغ الانتخاب', content: 'تبلغ محاضر انتخاب رئيس الهيئة الوطنية للمفوضين القضائيين إلى الوكيل العام للملك لدى محكمة الاستئناف بالرباط داخل أجل 15 يوما الموالية لهذه الانتخابات.'),
  DecreeArticle(id: '29', title: 'الجمع بين المهام', content: 'يجوز للمفوض القضائي أن يجمع بين صفته كمفوض قضائي وصفته كعضو أو رئيس للهيئة الوطنية للمفوضين القضائيين وصفته كعضو أو رئيس للمجلس الجهوي.\\nلا يمكن الجمع بين رئاسة الهيئة الوطنية للمفوضين القضائيين ورئاسة المجلس الجهوي للمفوضين القضائيين.'),
  DecreeArticle(id: '30', title: 'صلاحيات رئيس الهيئة', content: 'يمارس رئيس الهيئة الوطنية للمفوضين القضائيين جميع الصلاحيات اللازمة لضمان حسن سير الهيئة، والقيام بالمهام المسندة إليها بمقتضى هذا المرسوم.\\nيمثل الهيئة في الحياة المدنية تجاه الإدارة والغير.\\nيقبل الهبات والوصايا والإعانات المقدمة للهيئة.\\nيحق له أن يفوض إلى أحد نوابه أو إلى أحد أعضاء المكتب التنفيذي ممارسة بعض صلاحياته.\\nيبدي الرأي داخل اللجان التي تحدثها وزارة العدل عند النظر في كل ما يتعلق بالمهنة.'),
  DecreeArticle(id: '31', title: 'المكتب التنفيذي', content: 'يتكون المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين من رئيس الهيئة الوطنية ورؤساء المجالس الجهوية.\\nيتألف المكتب التنفيذي من:\\n- رئيس وهو رئيس الهيئة الوطنية للمفوضين القضائيين ؛\\n- نائب للرئيس ؛\\n- كاتب عام ؛\\n- نائب له ؛\\n- أمين المال ؛\\n- نائب له ؛\\n- الباقي مستشارون.\\nيتم توزيع المهام بين أعضاء المكتب التنفيذي بواسطة الاقتراع الفردي السري المباشر وبالأغلبية النسبية.'),
  DecreeArticle(id: '32', title: 'صلاحيات المكتب التنفيذي', content: 'يمارس المكتب التنفيذي بالإضافة إلى الاختصاصات المسندة إلى الهيئة بمقتضى هذا المرسوم، ودون المساس بالمهام المخولة إلى رئيس الهيئة، المهام التالية:\\n- ينسق عمل المجالس الجهوية ويسهر على حسن سيرها ؛\\n- يتولى وضع النظام الداخلي وتعديله، وفق ما يتطلبه تطبيق قواعد المهنة وتقاليدها وأعرافها، مع تبليغ نسخة منه إلى وزارة العدل وإلى الوكلاء العامين للملك لدى محاكم الاستئناف وإلى المجالس الجهوية ؛\\n- يتخذ التدابير اللازمة بصفة مؤقتة لفترة لا تتجاوز أربعة أشهر، عند تعذر تجديد مكتب أحد المجالس الجهوية كليا أو جزئيا، أو في حالة نشوب خلاف بين أعضائه أثر على حسن سيره وذلك ريثما يتم تجديده بصفة قانونية خلال الأجل المشار إليه أعلاه ؛\\n- يقوم بعد إذن وزير العدل بطبع وتوفير السجل والكناش المشار إليهما في المادة 15 من هذا المرسوم وتحديد ثمن بيعهما وتوزيعهما على المجالس الجهوية التي تضعهما رهن إشارة المفوضين القضائيين في الوقت المناسب، ويمكن لوزارة العدل ضمانا لحسن سير الإجراءات القضائية سحب الإذن المذكور كلما اقتضت المصلحة ذلك، والقيام بطبع وتوزيع ما ذكر أعلاه ؛\\n- يسهر على كيفية استيفاء واجب الاشتراك السنوي، ويحدد القسط الذي يخص المجالس الجهوية منها ؛\\n- يبرم عقود التأمين والاحتياط الاجتماعي أو التقاعد الخاصة بالمهنة ؛\\n- يبدي رأيه فيما يعرض عليه من مسائل تتعلق بالممارسة العامة للمهنة ومشاريع القوانين والأنظمة المتعلقة بمزاولتها ؛\\n- ينظم ندوات علمية للمتدربين، ويقيم أياما دراسية عند الاقتضاء.'),
  DecreeArticle(id: '33', title: 'اجتماعات المكتب', content: 'يجتمع المكتب التنفيذي بدعوة من رئيسه مرة كل ثلاثة أشهر على الأقل واستثناء كلما استلزم الأمر ذلك.\\nيمكن لثلثي أعضاء المكتب التنفيذي الدعوة إلى عقد اجتماع استثنائي للمكتب.'),
  DecreeArticle(id: '34', title: 'مداولات المكتب', content: 'تكون مداولات المكتب التنفيذي صحيحة إذا حضرها أعضاؤه، وإذا لم يتوفر ذلك جاز للمكتب التداول إذا حضر أكثر من نصف أعضائه.\\nتكون مداولات المكتب التنفيذي غير علنية.\\nتسجل مداولات المكتب التنفيذي في محضر يوقع عليه جميع الأعضاء الحاضرين، وفي حالة الرفض يشار إلى ذلك.'),
  DecreeArticle(id: '35', title: 'المجلس الجهوي', content: 'يضم المجلس الجهوي للمفوضين القضائيين وجوبا جميع المفوضين القضائيين المزاولين بدائرة محكمة الاستئناف.\\nيكون مقر كل مجلس جهوي بالمدينة التي توجد بها محكمة الاستئناف.\\nيتمتع المجلس الجهوي بالشخصية المعنوية.'),
  DecreeArticle(id: '36', title: 'مهام المجلس الجهوي', content: 'يزاول المجلس الجهوي للمفوضين القضائيين بواسطة مكتبه المهام التالية:\\n- السهر على تطبيق مقررات المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين ؛\\n- بحث المشاكل الجهوية التي تعترض المهنة، وإحالتها إن اقتضى الأمر على المكتب التنفيذي لتدارسها ؛\\n- تأطير وتمثيل المهنة على المستوى الجهوي ؛\\n- إشعار رئيس المحكمة الابتدائية المختص ووكيل الملك لديها، عند الاقتضاء بكل إخلال بالواجبات المهنية ؛\\n- إبداء النظر فيما يعرض عليه من طرف رئيس المحكمة الابتدائية المختص أو وكيل الملك لديها من إخلالات مهنية منسوبة لأي مفوض قضائي ؛\\n- تنظيم تظاهرات ثقافية وعلمية ؛\\n- إدارة ممتلكات المجلس الجهوي ؛\\n- إنشاء وإدارة مشاريع اجتماعية لفائدة المفوضين القضائيين ؛\\n- وضع النظام الداخلي وتعديله.'),
  DecreeArticle(id: '37', title: 'مكتب المجلس الجهوي', content: 'يتكون مكتب المجلس الجهوي للمفوضين القضائيين من رئيس هذا الأخير بصفته رئيسا له، بالإضافة إلى 8 أعضاء وهم:\\n- نائب للرئيس ؛\\n- كاتب عام ؛\\n- نائب له ؛\\n- أمين المال ؛\\n- نائب له ؛\\n- الباقي مستشارون.\\nيتم توزيع المهام بين أعضاء مكتب المجلس الجهوي بواسطة الاقتراع الفردي السري المباشر وبالأغلبية النسبية.\\nعلى أنه إذا كان عدد المفوضين القضائيين المسجلين على صعيد محكمة الاستئناف يقل عن خمسة وثلاثين مفوضا قضائيا فإنهم يلحقون بالمجلس الجهوي لأقرب محكمة استئناف.'),
  DecreeArticle(id: '38', title: 'ناخبو المجلس الجهوي', content: 'يتمتع بصفة ناخب المفوض القضائي الذي يزاول مهامه بمنطقة اختصاص المجلس الجهوي للمفوضين القضائيين بالإضافة إلى الشرطين المذكورين في المادة 23 أعلاه.'),
  DecreeArticle(id: '39', title: 'شروط عضوية المجلس الجهوي', content: 'يشترط في المترشح لعضوية مكتب المجلس الجهوي الشروط التالية:\\n- أن تكون له صفة ناخب ؛\\n- أن تكون له أقدمية خمس سنوات في ممارسة المهنة، ما لم يتعلق الأمر بمنصب الرئيس الذي يشترط فيه أقدمية سبع سنوات ؛\\n- أن لا يكون قد صدرت في حقه عقوبة تأديبية باستثناء عقوبة الإنذار ؛\\n- أن لا يكون محكوما عليه أو متابعا في قضية تمس بالشرف والمروءة.'),
  DecreeArticle(id: '40', title: 'انتخابات المجلس الجهوي', content: 'ينتخب رئيس وأعضاء مكتب المجلس الجهوي للمفوضين القضائيين خلال النصف الأخير من شهر مارس من طرف المفوضين القضائيين المزاولين مهامهم بمنطقة اختصاص المجلس الجهوي.\\nيعتبر فائزا المترشح الذي حصل على أكبر عدد من الأصوات المعبر عنها.'),
  DecreeArticle(id: '41', title: 'لوائح الترشيح والطعن', content: 'يصدر مكتب المجلس الجهوي خلال النصف الأول من شهر يناير من السنة التي تجري فيها الانتخابات مقررا بتحديد أسماء المفوضين القضائيين المتوفرين على الشروط المطلوبة قانونا ويعلق بمقر المجلس الجهوي داخل الأجل المذكور.\\nيحق لكل مفوض قضائي لم يرد اسمه في مقرر المجلس الجهوي الطعن فيه أمام المحكمة الإدارية المختصة جهويا داخل أجل ثمانية أيام من تاريخ التعليق وتبت داخل أجل 15 يوما من تاريخ إيداع الطعن بكتابة ضبط المحكمة وذلك بحكم غير قابل لأي طعن.\\nتوجه إلى مكتب المجلس الجهوي الترشيحات لرئاسة وعضوية مكتب المجلس داخل أجل شهر من تاريخ تعليق المقرر.'),
  DecreeArticle(id: '42', title: 'مدة التجديد والتبليغ', content: 'ينتخب رئيس وأعضاء مكتب المجلس الجهوي للمفوضين القضائيين لمدة ثلاث سنوات قابلة للتجديد مرة واحدة على الأكثر.\\nتبلغ محاضر انتخاب رئيس وأعضاء مكتب المجلس الجهوي إلى الوكيل العام للملك لدى محكمة الاستئناف الواقع بدائرتها مكتب المجلس الجهوي وإلى جميع وكلاء الملك التابعين لنفس محكمة الاستئناف وإلى المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين داخل أجل 15 يوما الموالية لهذه الانتخابات.'),
  DecreeArticle(id: '43', title: 'صلاحيات رئيس المجلس', content: 'يمارس رئيس مكتب المجلس الجهوي الصلاحيات اللازمة لضمان حسن سير هذا المكتب، والقيام بالمهام المسندة إليه والسهر على تنفيذ مقررات المكتب التنفيذي للهيئة الوطنية للمفوضين القضائيين.\\nيمثل المجلس الجهوي للمفوضين القضائيين أمام القضاء ويدافع عن مصالح المفوضين القضائيين جهويا ويحق له إحالة أية نازلة على رئيس الهيئة الوطنية لاتخاذ المتعين.\\nيوجه الدعوة للانعقاد اجتماع مكتب المجلس الجهوي، يحدد جدول أعماله ويتولى تنفيذ المقررات الصادرة عنه، وله أن يفوض بعض صلاحياته إلى أحد أعضاء المكتب.'),
  DecreeArticle(id: '44', title: 'مداولات المجلس الجهوي', content: 'يجتمع مكتب المجلس الجهوي للمفوضين القضائيين طبقا للمسطرة المنصوص عليها في المادة 33 أعلاه، كما تتم مداولاته وفق مقتضيات المادة 34 أعلاه.'),
  DecreeArticle(id: '45', title: 'مسك الحسابات', content: 'يقوم أمين مال الهيئة الوطنية وأمناء مال المجالس الجهوية، كل حسب اختصاصاته باستخلاص الموارد وبأداء النفقات وبمسك الحسابات، وفق ما ينص عليه النظام الداخلي والقوانين الجاري بها العمل فيما يتعلق بمسك الحسابات.'),
  DecreeArticle(id: '46', title: 'لجان المراقبة', content: 'تنتخب كل ثلاث سنوات من طرف الجمعية العامة للهيئة الوطنية بالأغلبية وبواسطة الاقتراع السري لجنة لمراقبة مالية الهيئة الوطنية تتكون من ثلاثة أعضاء رسميين وثلاثة أعضاء نواب من غير أعضاء المكتب التنفيذي للهيئة الوطنية ولجان للمراقبة على صعيد المجالس الجهوية تتكون من ثلاثة أعضاء رسميين وثلاثة أعضاء نواب من غير أعضاء مكاتب المجالس الجهوية.'),
  DecreeArticle(id: '47', title: 'اجتماع واختصاص اللجان', content: 'تجتمع اللجان المذكورة مرة واحدة في السنة على الأقل.\\nتتولى اللجان المذكورة كل حسب اختصاصها:\\n- التدقيق في نظامية العمليات المحاسبية للهيئة الوطنية أو المجالس الجهوية ؛\\n- مراقبة مسك المحاسبة للهيئة الوطنية أو المجالس الجهوية ؛\\nتدون نتائج أشغالها في تقرير كتابي يطلع عليه رئيس الهيئة الوطنية أو رئيس المجلس الجهوي حسب كل حالة قبل إحالتها على الجمعية العامة أو المجلس الجهوي.'),
  DecreeArticle(id: '48', title: 'مقتضيات انتقالية جهوية', content: 'تحدث وزارة العدل لجانا على صعيد دوائر محاكم الاستئناف تتألف كل واحدة منها من مستشارين اثنين على الأقل بمحكمة الاستئناف، ونائبين للوكيل العام للملك لديها، وستة مفوضين قضائيين يتم اختيارهم من بين المفوضين القضائيين بدائرة نفس المحكمة، على أن لا يكونوا من بين المترشحين لمنصب رئيس المجلس الجهوي أو لعضوية مكتبه، يعهد إليها في أجل أقصاه سنة من تاريخ سريان العمل بهذا المرسوم بالإشراف على تأسيس المجالس الجهوية وانتخاب رؤسائها وأعضاء مكاتبها بقصد إحداث الهيئة الوطنية للمفوضين القضائيين، وفق الشروط والإجراءات المنصوص عليها في هذا المرسوم دون التقيد - عند الاقتضاء بالتواريخ المحددة في المواد المشار إليها أعلاه.'),
  DecreeArticle(id: '49', title: 'مقتضيات انتقالية وطنية', content: 'يعهد إلى الرئيس الأول لمحكمة الاستئناف بالرباط والوكيل العام للملك لديها، بالإشراف على تكوين لجنة تتألف من أربعة قضاة من الدرجة الثانية على الأقل، اثنان منهم من قضاء الحكم واثنان من النيابة العامة، وأربعة مفوضين قضائيين من دائرة نفس المحكمة شريطة أن لا يكونوا من بين أعضاء مكتب المجلس الجهوي أو مترشحين لمنصب رئيس الهيئة الوطنية للمفوضين القضائيين.\\nتسهر هذه اللجنة تحت إشراف الرئيس الأول لنفس المحكمة والوكيل العام للملك لديها، أو من ينوب عنهما عند الاقتضاء، على اتخاذ جميع الإجراءات الرامية إلى انتخاب رئيس الهيئة الوطنية للمفوضين القضائيين، وفقا لمقتضيات المنصوص عليها في هذا المرسوم.'),
  DecreeArticle(id: '50', title: 'انحلال اللجان الانتقالية', content: 'تنحل اللجان المشار إليها، بمجرد انتهاء المهام المسندة إليها بمقتضى المادتين السابقتين.'),
  DecreeArticle(id: '51', title: 'نسخ المقتضيات المخالفة', content: 'تنسخ جميع المقتضيات المخالفة ولا سيما مقتضيات المرسوم 2.85.736 الصادر في 21 ربيع الآخر 1407 (24 ديسمبر 1986) بتطبيق أحكام القانون رقم 41.80 المتعلق بإحداث هيئة للأعوان القضائيين وتنظيمها الصادر بتنفيذه الظهير الشريف رقم 1.80.440 بتاريخ 17 من صفر 1401 (25 ديسمبر 1980).'),
  DecreeArticle(id: '52', title: 'تنفيذ المرسوم', content: 'يسند تنفيذ هذا المرسوم الذي ينشر في الجريدة الرسمية إلى وزير العدل ووزير الاقتصاد والمالية كل واحد فيما يخصه.'),
];
"""

with codecs.open('c:/src/nour/lib/models/library_data.dart', 'r', encoding='utf-8') as f:
    content = f.read()

content = re.sub(r'const List<DecreeArticle> decreeData = \[.*?\];', new_decree_data, content, flags=re.DOTALL)

with codecs.open('c:/src/nour/lib/models/library_data.dart', 'w', encoding='utf-8') as f:
    f.write(content)

print("DECREE INJECTION SUCCESSFUL")
